fun solve(sx: Long, sy: Long, tx: Long, ty: Long): Long {
    // If the starting point is the target, no moves are needed
    if (sx == tx && sy == ty) return 0

    // If the target is not reachable, return -1
    if (sx > tx || sy > ty) return -1

    var x = sx
    var y = sy
    var steps = 0

    // Move towards the target in a way that ensures we can reach the target
    while (x < tx || y < ty) {
        val m = max(x, y)
        if (x < tx && y < ty) {
            // If both coordinates are less than the target, we can move in either direction
            // Choose the direction that brings us closer to the target
            if (tx - x > ty - y) {
                x += m
            } else {
                y += m
            }
        } else if (x < tx) {
            x += m
        } else {
            y += m
        }
        steps++
    }

    return steps
}
